    20→template <class ResponseProto> using ResponseProtoPtr = std::unique_ptr<ResponseProto>;
    21→
    22→// Oversees communication for gRPC xDS implementations (parent to both regular xDS and delta
    23→// xDS variants). Reestablishes the gRPC channel when necessary, and provides rate limiting of
    24→// requests.
    25→template <class RequestProto, class ResponseProto>
    26→class GrpcStream : public GrpcStreamInterface<RequestProto, ResponseProto>,
    27→                   public Logger::Loggable<Logger::Id::config> {
    28→public:
    29→  GrpcStream(GrpcStreamCallbacks<ResponseProto>* callbacks, Grpc::RawAsyncClientPtr async_client,
    30→             const Protobuf::MethodDescriptor& service_method, Event::Dispatcher& dispatcher,
    31→             Stats::Scope& scope, BackOffStrategyPtr backoff_strategy,
    32→             const RateLimitSettings& rate_limit_settings)
    33→      : callbacks_(callbacks), async_client_(std::move(async_client)),
    34→        service_method_(service_method),
    35→        control_plane_stats_(Utility::generateControlPlaneStats(scope)),
    36→        time_source_(dispatcher.timeSource()), backoff_strategy_(std::move(backoff_strategy)),
    37→        rate_limiting_enabled_(rate_limit_settings.enabled_) {
    38→    retry_timer_ = dispatcher.createTimer([this]() -> void { establishNewStream(); });
    39→    if (rate_limiting_enabled_) {
    40→      // Default Bucket contains 100 tokens maximum and refills at 10 tokens/sec.
    41→      limit_request_ = std::make_unique<TokenBucketImpl>(
    42→          rate_limit_settings.max_tokens_, time_source_, rate_limit_settings.fill_rate_);
    43→      drain_request_timer_ = dispatcher.createTimer([this]() {
    44→        if (stream_ != nullptr) {
    45→          callbacks_->onWriteable();
    46→        }
    47→      });
    48→    }
    49→  }
    50→
    51→  void establishNewStream() override {
    52→    stream_intentionally_closed_ = false;
    53→    ENVOY_LOG(debug, "Establishing new gRPC bidi stream to {} for {}", async_client_.destination(),
    54→              service_method_.DebugString());
    55→    if (stream_ != nullptr) {
    56→      ENVOY_LOG(warn, "gRPC bidi stream to {} for {} already exists!", async_client_.destination(),
    57→                service_method_.DebugString());
    58→      return;
    59→    }
    60→    stream_ = async_client_->start(service_method_, *this, Http::AsyncClient::StreamOptions());
    61→    if (stream_ == nullptr) {
    62→      ENVOY_LOG(debug, "Unable to establish new stream to configuration server {}",
    63→                async_client_.destination());
    64→      callbacks_->onEstablishmentFailure();
    65→      setRetryTimer();
    66→      return;
    67→    }
    68→    control_plane_stats_.connected_state_.set(1);
    69→    callbacks_->onStreamEstablished();
    70→  }
    71→
    72→  bool grpcStreamAvailable() const override { return stream_ != nullptr; }
    73→
    74→  void sendMessage(const RequestProto& request) override { stream_->sendMessage(request, false); }
