   113→  void maybeUpdateQueueSizeStat(uint64_t size) override {
   114→    // Although request_queue_.push() happens elsewhere, the only time the queue is non-transiently
   115→    // non-empty is when it remains non-empty after a drain attempt. (The push() doesn't matter
   116→    // because we always attempt this drain immediately after the push). Basically, a change in
   117→    // queue length is not "meaningful" until it has persisted until here. We need the
   118→    // if(>0 || used) to keep this stat from being wrongly marked interesting by a pointless set(0)
   119→    // and needlessly taking up space. The first time we set(123), used becomes true, and so we will
   120→    // subsequently always do the set (including set(0)).
   121→    if (size > 0 || control_plane_stats_.pending_requests_.used()) {
   122→      control_plane_stats_.pending_requests_.set(size);
   123→    }
   124→  }
